import{_ as o,o as a,c as t,a2 as r}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[LOGIC / BUSINESS] F-05.4 — Acciones Backend: Rutas Web y Livewire Actions","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-05.4_api_rest_crud.md","filePath":"backlog/F-05.4_api_rest_crud.md","lastUpdated":null}'),s={name:"backlog/F-05.4_api_rest_crud.md"};function i(n,e,c,d,l,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="logic-business-f-05-4-—-acciones-backend-rutas-web-y-livewire-actions" tabindex="-1">[LOGIC / BUSINESS] F-05.4 — Acciones Backend: Rutas Web y Livewire Actions <a class="header-anchor" href="#logic-business-f-05-4-—-acciones-backend-rutas-web-y-livewire-actions" aria-label="Permalink to &quot;[LOGIC / BUSINESS] F-05.4 — Acciones Backend: Rutas Web y Livewire Actions&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-05 — Infraestructura y Conectividad</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Logic / Business</code><strong>Impacta en:</strong> Equipo Backend (Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.1_setup_laravel_livewire.html">F-00.1</a></td><td>Base Laravel instalada</td></tr><tr><td><a href="./F-00.3_layout_navegacion.html">F-00.3</a></td><td>Vistas Blade que los controladores retornan (layout base disponible)</td></tr><tr><td><a href="./F-05.3_autenticacion_admin.html">F-05.3</a></td><td>Middleware <code>auth</code> activo para proteger todas las rutas web</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como desarrollador Quiero que todos los controladores y Livewire Actions del panel estén bien estructurados y protegidos Para que las operaciones sobre logs, histórico, error codes y comentarios sean predecibles, seguras y mantenibles</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Rutas web protegidas):</strong> Dado que el panel usa Livewire (SSR), cuando se definen las rutas en <code>routes/web.php</code>, entonces todas están dentro del grupo <code>middleware:auth</code> y retornan vistas Blade.</li><li>[ ] <strong>Escenario 2 (Controladores por responsabilidad):</strong> Los 4 controladores del proyecto son: <code>DashboardController</code>, <code>LogController</code>, <code>ArchivedLogController</code>, <code>ErrorCodeController</code>. Cada uno gestiona solo sus rutas.</li><li>[ ] <strong>Escenario 3 (Livewire Actions validadas):</strong> Dado que un Livewire Action recibe datos del usuario (texto, IDs), cuando se ejecuta, entonces valida la entrada con <code>$this-&gt;validate()</code> antes de cualquier operación de DB.</li><li>[ ] <strong>Escenario 4 (Autorización en acciones):</strong> Dado que se ejecuta una acción de borrado o edición, cuando se procesa, entonces Laravel Policies o <code>$this-&gt;authorize()</code> verifican que el usuario actual tiene permiso.</li><li>[ ] <strong>Escenario 5 (SSE con middleware):</strong> Dado que existe el endpoint <code>GET /sse/logs</code>, cuando un cliente sin sesión válida lo solicita, entonces recibe un <code>401</code> (redirige a login) y no se abre el stream.</li><li>[ ] <strong>Requisito Técnico:</strong> Rutas mínimas en <code>routes/web.php</code>: <code>GET /</code>, <code>GET /dashboard</code>, <code>GET /logs</code>, <code>GET /logs/{id}</code>, <code>GET /historico</code>, <code>GET /historico/{id}</code>, <code>GET /error-codes</code>, <code>GET /error-codes/{id}</code>, <code>DELETE /historico/{id}</code>, <code>POST /logout</code>, <code>GET /sse/logs</code>. Sin prefijo <code>/api</code> (no hay SPA). Livewire Actions gestionan el resto (filtros, archivado, comentarios, CRUD). Usar <code>FormRequest</code> o reglas inline para validación.</li></ul><hr><p><strong>MoSCoW:</strong> <code>MUST</code><strong>Sprint:</strong> Sprint 0</p><p><strong>Notas:</strong></p><ul><li>Con Livewire, la mayoría de operaciones que antes eran endpoints REST ahora son Livewire Actions (llamadas internas al servidor via wire protocol).</li><li>El único endpoint &quot;convencional&quot; que no es Livewire es el SSE (<code>GET /sse/logs</code>) que usa <code>StreamedResponse</code>.</li><li>No se necesita Laravel Sanctum ni tokens API para el frontend — la sesión web de Laravel es suficiente.</li></ul>',16)])])}const h=o(s,[["render",i]]);export{g as __pageData,h as default};
